code = """import json
import re

with open(locals()['var_function-call-7732815880617685738'], 'r') as f:
    papers = json.load(f)

def get_year(text):
    # Check start and end
    snippets = [text[:2000], text[-2000:]]
    combined = "\n".join(snippets)
    
    # Check for specific conference patterns with 2016 or '16
    conf_pattern = r"(CHI|DIS|UbiComp|CSCW|IUI|TEI|AH|OzCHI|PervasiveHealth|WWW)\s*('16|2016)"
    if re.search(conf_pattern, combined, re.IGNORECASE):
        return 2016
    
    # Check for Copyright/Permission with 2016
    if re.search(r"(Copyright|Permission|ACM).{0,300}2016", combined, re.DOTALL | re.IGNORECASE):
        return 2016
        
    # Check for date line like "June 2016", "September 2016"
    if re.search(r"(January|February|March|April|May|June|July|August|September|October|November|December).{0,20}2016", combined, re.IGNORECASE):
        return 2016

    return None

matches = []
for paper in papers:
    text = paper['text']
    filename = paper['filename']
    
    # Check domain
    if 'physical activity' in text.lower():
        year = get_year(text)
        if year == 2016:
            matches.append(filename)

print("__RESULT__:")
print(json.dumps(matches))"""

